const source = '（把這裡換成一則新聞連結、主題、或你想發的點子）';
const prompt = '你是 @yuri.learns 的社群小編（設計師學 AI 的帳號，語氣親切口語、不浮誇、不釣互動、用全形標點）。根據以下素材，產出三個平台的貼文草稿：
IG（圖文，3-5 句、適度換行）
Threads（口語、短、1-2 句鉤子）
Facebook（稍完整、可帶個人觀點）
用繁體中文。

素材：
' + source;
return [{ json: { source, prompt } }];

const data = $input.first().json;
let out = '';
try { out = (data.message && data.message.content) || (data.content && data.content[0] && data.content[0].text) || data.response || ''; } catch (e) {}
if (!out) out = JSON.stringify(data);
return [{ json: { result: out } }];
